/**
 * CLI Proxy Setup Acceptance Test Kit
 *
 * Domain-specific helpers for proxy token and CLI proxy setup tests.
 * Extends the shared acceptance-test-kit and llm-proxy-test-kit with
 * proxy token issuance, validation, and CLI config helpers.
 *
 * Driving ports:
 *   - POST /api/auth/proxy-token (issue proxy tokens)
 *   - POST /proxy/llm/anthropic/v1/messages (proxy with Brain auth)
 *   - CLI config files (~/.brain/config.json, .claude/settings.local.json)
 */
import { RecordId, type Surreal } from "surrealdb";
import {
  setupAcceptanceSuite,
  createTestUser,
  fetchRaw,
  type AcceptanceTestRuntime,
  type TestUser,
} from "../acceptance-test-kit";
import {
  createProxyTestWorkspace,
  buildProxyRequestBody,
} from "../llm-proxy/llm-proxy-test-kit";

// Re-export shared helpers
export {
  setupAcceptanceSuite,
  createTestUser,
  fetchRaw,
  createProxyTestWorkspace,
  type AcceptanceTestRuntime,
  type TestUser,
};

export type { ProxyTestUser };

// ---------------------------------------------------------------------------
// Proxy Token Issuance Helpers
// ---------------------------------------------------------------------------

export type ProxyTokenResponse = {
  proxy_token: string;
  expires_at: string;
  workspace_id: string;
};

/**
 * Request a proxy token from the server, simulating what `brain init` Step 7 does.
 *
 * The endpoint validates via Better Auth session cookies (not the Bearer value).
 * Pass sessionHeaders from createProxyTestUser() which contains Cookie header.
 * A dummy Authorization: Bearer header is included to satisfy the parse check.
 */
export async function requestProxyToken(
  baseUrl: string,
  sessionHeaders: Record<string, string>,
  workspaceId: string,
): Promise<Response> {
  return fetch(`${baseUrl}/api/auth/proxy-token`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": "Bearer session-via-cookie",
      ...sessionHeaders,
    },
    body: JSON.stringify({ workspace_id: workspaceId }),
  });
}

// ---------------------------------------------------------------------------
// Full Proxy Test User Setup
// ---------------------------------------------------------------------------

export type ProxyTestUser = {
  sessionHeaders: Record<string, string>;
  workspaceId: string;
  identityId: string;
  personId: string;
};

/**
 * Create a fully-wired test user for proxy token tests.
 *
 * Pipeline:
 *   1. Sign up via Better Auth → session cookies + person ID
 *   2. Create workspace
 *   3. Create identity with identity_person edge (person → identity)
 *   4. Create member_of edge (identity → workspace)
 *
 * Returns session headers (cookies) for use with requestProxyToken().
 */
export async function createProxyTestUser(
  baseUrl: string,
  surreal: Surreal,
  suffix: string,
): Promise<ProxyTestUser> {
  const workspaceId = `ws-${suffix}-${crypto.randomUUID()}`;
  const identityId = `id-${suffix}-${crypto.randomUUID()}`;

  // 1. Create real Better Auth user → session cookies
  const email = `proxy-${Date.now()}-${suffix}@test.local`;
  const signUpResponse = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ name: "Proxy Test User", email, password: "test-password-123" }),
    redirect: "manual",
  });

  if (!signUpResponse.ok) {
    const body = await signUpResponse.text();
    throw new Error(`Failed to create proxy test user (${signUpResponse.status}): ${body}`);
  }

  const setCookie = signUpResponse.headers.getSetCookie();
  if (!setCookie || setCookie.length === 0) {
    throw new Error("Sign-up did not return session cookies");
  }

  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
  const sessionHeaders: Record<string, string> = { Cookie: cookieHeader };

  // Extract person ID from sign-up response body
  const signUpBody = await signUpResponse.json() as { user?: { id?: string } };
  const personId = signUpBody.user?.id;
  if (!personId) {
    throw new Error("Sign-up response did not include user ID");
  }

  // 2. Create workspace
  await createProxyTestWorkspace(surreal, workspaceId);

  // 3. Create identity
  const identityRecord = new RecordId("identity", identityId);
  const workspaceRec = new RecordId("workspace", workspaceId);
  const personRecord = new RecordId("person", personId);

  await surreal.query(`CREATE $identity CONTENT $content;`, {
    identity: identityRecord,
    content: {
      name: "Proxy Test User",
      type: "human",
      role: "owner",
      workspace: workspaceRec,
      created_at: new Date(),
    },
  });

  // 4. Create identity_person edge (identity → person)
  await surreal.query(
    `RELATE $identity->identity_person->$person SET added_at = time::now();`,
    { identity: identityRecord, person: personRecord },
  );

  // 5. Create member_of edge (identity → workspace)
  await surreal.query(
    `RELATE $identity->member_of->$workspace SET role = "admin", added_at = time::now();`,
    { identity: identityRecord, workspace: workspaceRec },
  );

  return { sessionHeaders, workspaceId, identityId, personId };
}

// ---------------------------------------------------------------------------
// Brain-Auth Proxy Request Helpers
// ---------------------------------------------------------------------------

/**
 * Send a proxy request using Brain auth (X-Brain-Auth header) instead of
 * direct Anthropic API key. This is how Claude Code routes through the proxy
 * after `brain init` configures settings.local.json.
 */
export async function sendBrainAuthProxyRequest(
  baseUrl: string,
  proxyToken: string,
  options?: {
    model?: string;
    maxTokens?: number;
    messages?: Array<{ role: string; content: string }>;
    stream?: boolean;
  },
): Promise<Response> {
  const body = buildProxyRequestBody({
    model: options?.model ?? "claude-sonnet-4-20250514",
    maxTokens: options?.maxTokens ?? 20,
    messages: options?.messages ?? [{ role: "user", content: "Say exactly: test" }],
    stream: options?.stream ?? false,
  });

  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "anthropic-version": "2023-06-01",
      "X-Brain-Auth": proxyToken,
    },
    body,
  });
}

// ---------------------------------------------------------------------------
// Proxy Token DB Helpers
// ---------------------------------------------------------------------------

export type ProxyTokenRecord = {
  id: RecordId;
  token_hash: string;
  workspace: RecordId;
  identity: RecordId;
  expires_at: Date;
  created_at: Date;
  revoked: boolean;
};

/**
 * Query all proxy tokens for an identity+workspace pair.
 */
export async function getProxyTokensForIdentity(
  surreal: Surreal,
  identityId: string,
  workspaceId: string,
): Promise<ProxyTokenRecord[]> {
  const identityRecord = new RecordId("identity", identityId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  const results = await surreal.query(
    `SELECT * FROM proxy_token WHERE identity = $identity AND workspace = $ws ORDER BY created_at DESC;`,
    { identity: identityRecord, ws: workspaceRecord },
  );

  return (results[0] ?? []) as ProxyTokenRecord[];
}

/**
 * Count active (non-revoked, non-expired) proxy tokens for an identity+workspace.
 */
export async function countActiveProxyTokens(
  surreal: Surreal,
  identityId: string,
  workspaceId: string,
): Promise<number> {
  const identityRecord = new RecordId("identity", identityId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  const results = await surreal.query(
    `SELECT count() AS total FROM proxy_token WHERE identity = $identity AND workspace = $ws AND revoked = false AND expires_at > time::now() GROUP ALL;`,
    { identity: identityRecord, ws: workspaceRecord },
  );

  const rows = (results[0] ?? []) as Array<{ total: number }>;
  return rows[0]?.total ?? 0;
}

/**
 * Seed an expired proxy token for testing expiry detection scenarios.
 */
export async function seedExpiredProxyToken(
  surreal: Surreal,
  tokenId: string,
  options: {
    tokenHash: string;
    workspaceId: string;
    identityId: string;
    expiredDaysAgo?: number;
  },
): Promise<string> {
  const tokenRecord = new RecordId("proxy_token", tokenId);
  const workspaceRecord = new RecordId("workspace", options.workspaceId);
  const identityRecord = new RecordId("identity", options.identityId);
  const daysAgo = options.expiredDaysAgo ?? 1;
  const expiredAt = new Date(Date.now() - daysAgo * 24 * 60 * 60 * 1000);

  await surreal.query(`CREATE $tkn CONTENT $content;`, {
    tkn: tokenRecord,
    content: {
      token_hash: options.tokenHash,
      workspace: workspaceRecord,
      identity: identityRecord,
      expires_at: expiredAt,
      created_at: new Date(expiredAt.getTime() - 90 * 24 * 60 * 60 * 1000),
      revoked: false,
    },
  });

  return tokenId;
}

// ---------------------------------------------------------------------------
// CLI Config Simulation Helpers
// ---------------------------------------------------------------------------

/**
 * Build what brain init Step 7 should write to .claude/settings.local.json.
 * Used for asserting CLI output correctness.
 */
export function buildExpectedSettingsLocal(
  serverUrl: string,
  proxyToken: string,
): Record<string, unknown> {
  return {
    env: {
      ANTHROPIC_BASE_URL: `${serverUrl}/proxy/llm/anthropic`,
      ANTHROPIC_HEADERS: `X-Brain-Auth: ${proxyToken}`,
    },
  };
}

/**
 * Build what brain init Step 7 should store in ~/.brain/config.json repo entry.
 */
export function buildExpectedRepoConfig(
  proxyToken: string,
  expiresAt: string,
): { proxy_token: string; proxy_token_expires_at: string } {
  return {
    proxy_token: proxyToken,
    proxy_token_expires_at: expiresAt,
  };
}

// ---------------------------------------------------------------------------
// Identity + Workspace Setup (for OAuth simulation in tests)
// ---------------------------------------------------------------------------

/**
 * Create a test identity and workspace with member_of edge,
 * and return a simulated access token for proxy token issuance tests.
 *
 * Note: In real flow, access_token comes from OAuth. In acceptance tests,
 * we either use the acceptance-test-kit's createTestUser or seed directly.
 */
export async function createProxyTestIdentity(
  surreal: Surreal,
  options: {
    identityId: string;
    workspaceId: string;
    email?: string;
  },
): Promise<{ identityId: string; workspaceId: string }> {
  const identityRecord = new RecordId("identity", options.identityId);
  const workspaceRecord = new RecordId("workspace", options.workspaceId);

  // Create identity
  await surreal.query(`CREATE $identity CONTENT $content;`, {
    identity: identityRecord,
    content: {
      name: `Test User ${options.identityId}`,
      type: "human",
      workspace: workspaceRecord,
      created_at: new Date(),
    },
  });

  // Create member_of edge
  await surreal.query(
    `RELATE $identity->member_of->$workspace SET role = "admin", added_at = time::now();`,
    { identity: identityRecord, workspace: workspaceRecord },
  );

  return { identityId: options.identityId, workspaceId: options.workspaceId };
}

/**
 * Unit Tests: CLI Proxy Settings Pure Functions
 *
 * Tests the pure functions extracted for proxy config management:
 *   - mergeProxyEnvSettings: merge proxy env vars into settings object
 *   - checkSettingsGitignored: detect if settings.local.json is in .gitignore
 *
 * These are pure functions with no IO — they transform data in, data out.
 */
import { describe, expect, it } from "bun:test";
import {
  mergeProxyEnvSettings,
  checkSettingsGitignored,
} from "../../cli/proxy-settings";

// ---------------------------------------------------------------------------
// mergeProxyEnvSettings
// ---------------------------------------------------------------------------

describe("mergeProxyEnvSettings", () => {
  it("creates env block from empty settings", () => {
    const result = mergeProxyEnvSettings(
      {},
      "https://brain.example.com",
      "brp_abc123",
    );

    expect(result.env.ANTHROPIC_BASE_URL).toBe(
      "https://brain.example.com/proxy/llm/anthropic",
    );
    expect(result.env.ANTHROPIC_HEADERS).toBe("X-Brain-Auth: brp_abc123");
  });

  it("preserves existing non-Brain env vars", () => {
    const existing = {
      env: {
        MY_CUSTOM_VAR: "keep-this",
        ANOTHER_VAR: "also-keep",
      },
    };

    const result = mergeProxyEnvSettings(
      existing,
      "https://brain.example.com",
      "brp_xyz789",
    );

    expect(result.env.MY_CUSTOM_VAR).toBe("keep-this");
    expect(result.env.ANOTHER_VAR).toBe("also-keep");
    expect(result.env.ANTHROPIC_BASE_URL).toBe(
      "https://brain.example.com/proxy/llm/anthropic",
    );
    expect(result.env.ANTHROPIC_HEADERS).toBe("X-Brain-Auth: brp_xyz789");
  });

  it("preserves existing non-env config keys", () => {
    const existing = {
      permissions: { allow: ["Read", "Write"] },
      env: { SOME_KEY: "value" },
    };

    const result = mergeProxyEnvSettings(
      existing,
      "https://brain.example.com",
      "brp_token",
    );

    expect((result as Record<string, unknown>).permissions).toEqual({
      allow: ["Read", "Write"],
    });
    expect(result.env.SOME_KEY).toBe("value");
  });

  it("replaces proxy token on re-run", () => {
    const existing = {
      env: {
        ANTHROPIC_BASE_URL: "https://brain.example.com/proxy/llm/anthropic",
        ANTHROPIC_HEADERS: "X-Brain-Auth: brp_old_token",
        SOME_OTHER_KEY: "preserve-me",
      },
    };

    const result = mergeProxyEnvSettings(
      existing,
      "https://brain.example.com",
      "brp_new_token",
    );

    expect(result.env.ANTHROPIC_HEADERS).toBe("X-Brain-Auth: brp_new_token");
    expect(result.env.ANTHROPIC_BASE_URL).toBe(
      "https://brain.example.com/proxy/llm/anthropic",
    );
    expect(result.env.SOME_OTHER_KEY).toBe("preserve-me");
  });

  it("does not mutate the input object", () => {
    const existing = { env: { MY_KEY: "original" } };
    const copy = JSON.parse(JSON.stringify(existing));

    mergeProxyEnvSettings(existing, "https://brain.example.com", "brp_token");

    expect(existing).toEqual(copy);
  });

  it("always points to Brain proxy, never direct Anthropic URL", () => {
    const result = mergeProxyEnvSettings(
      {},
      "https://brain.example.com",
      "brp_token",
    );

    expect(result.env.ANTHROPIC_BASE_URL).not.toContain("api.anthropic.com");
    expect(result.env.ANTHROPIC_BASE_URL).toContain("/proxy/llm/anthropic");
  });
});

// ---------------------------------------------------------------------------
// checkSettingsGitignored
// ---------------------------------------------------------------------------

describe("checkSettingsGitignored", () => {
  it("returns false when gitignore content is undefined (no file)", () => {
    expect(checkSettingsGitignored(undefined)).toBe(false);
  });

  it("returns false when gitignore is empty", () => {
    expect(checkSettingsGitignored("")).toBe(false);
  });

  it("returns false when settings.local.json not listed", () => {
    expect(checkSettingsGitignored("node_modules/\n.env\n")).toBe(false);
  });

  it("returns true when .claude/settings.local.json is listed", () => {
    expect(
      checkSettingsGitignored("node_modules/\n.claude/settings.local.json\n"),
    ).toBe(true);
  });

  it("returns true when /.claude/settings.local.json is listed (leading slash)", () => {
    expect(
      checkSettingsGitignored("/.claude/settings.local.json\n"),
    ).toBe(true);
  });

  it("returns true when settings.local.json appears as bare filename", () => {
    expect(
      checkSettingsGitignored("settings.local.json\n"),
    ).toBe(true);
  });

  it("ignores comment lines", () => {
    expect(
      checkSettingsGitignored("# .claude/settings.local.json\n"),
    ).toBe(false);
  });

  it("handles whitespace around patterns", () => {
    expect(
      checkSettingsGitignored("  .claude/settings.local.json  \n"),
    ).toBe(true);
  });
});

/**
 * Acceptance Tests: CLI Settings Configuration
 *
 * Milestone 3: brain init Step 7 — .claude/settings.local.json management
 *
 * Tests the CLI's config file management:
 *   - Fresh setup creates settings.local.json with correct env vars
 *   - Existing settings are merged without data loss
 *   - Re-running brain init updates token in place
 *   - .gitignore verification and warning
 *   - ~/.brain/config.json proxy_token storage
 *
 * These tests exercise the CLI config functions directly (unit-level driving port)
 * rather than the full `brain init` flow, since the OAuth flow is tested elsewhere.
 *
 * Driving port: setupProxyConfig() from cli/commands/init.ts
 */
import { describe, expect, it, beforeEach, afterEach } from "bun:test";
import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";

// ---------------------------------------------------------------------------
// Test fixtures: temporary directories simulating repo + home
// ---------------------------------------------------------------------------
let tmpDir: string;
let repoDir: string;
let claudeDir: string;

beforeEach(() => {
  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "brain-proxy-test-"));
  repoDir = path.join(tmpDir, "repo");
  claudeDir = path.join(repoDir, ".claude");
  fs.mkdirSync(claudeDir, { recursive: true });
});

afterEach(() => {
  fs.rmSync(tmpDir, { recursive: true, force: true });
});

// ---------------------------------------------------------------------------
// Helpers: simulate the config write logic that setupProxyConfig() performs
// ---------------------------------------------------------------------------

/**
 * Simulates the settings.local.json write logic from brain init Step 7.
 * This is the behavior under test — the actual implementation in cli/commands/init.ts
 * should produce identical results.
 */
function writeSettingsLocal(
  settingsPath: string,
  serverUrl: string,
  proxyToken: string,
): void {
  let existing: Record<string, unknown> = {};
  if (fs.existsSync(settingsPath)) {
    existing = JSON.parse(fs.readFileSync(settingsPath, "utf-8"));
  }

  const env = (existing.env ?? {}) as Record<string, string>;
  env.ANTHROPIC_BASE_URL = `${serverUrl}/proxy/llm/anthropic`;
  env.ANTHROPIC_HEADERS = `X-Brain-Auth: ${proxyToken}`;

  existing.env = env;
  fs.writeFileSync(settingsPath, JSON.stringify(existing, undefined, 2) + "\n");
}

function isGitignored(repoPath: string, filePath: string): boolean {
  const gitignorePath = path.join(repoPath, ".gitignore");
  if (!fs.existsSync(gitignorePath)) return false;
  const patterns = fs.readFileSync(gitignorePath, "utf-8").split("\n");
  const relative = path.relative(repoPath, filePath);
  return patterns.some((p) => p.trim() === relative || p.trim() === `/${relative}`);
}

// ---------------------------------------------------------------------------
// Scenario: Fresh setup with no existing settings.local.json
// ---------------------------------------------------------------------------
describe("Fresh proxy setup", () => {
  it("creates .claude/settings.local.json with ANTHROPIC_BASE_URL and ANTHROPIC_HEADERS", () => {
    const settingsPath = path.join(claudeDir, "settings.local.json");

    // Given a repo with no .claude/settings.local.json
    expect(fs.existsSync(settingsPath)).toBe(false);

    // When the proxy setup step runs
    writeSettingsLocal(settingsPath, "https://brain.example.com", "brp_abc123");

    // Then .claude/settings.local.json is created with correct keys
    expect(fs.existsSync(settingsPath)).toBe(true);

    const content = JSON.parse(fs.readFileSync(settingsPath, "utf-8"));
    expect(content.env.ANTHROPIC_BASE_URL).toBe("https://brain.example.com/proxy/llm/anthropic");
    expect(content.env.ANTHROPIC_HEADERS).toBe("X-Brain-Auth: brp_abc123");
  });
});

// ---------------------------------------------------------------------------
// Scenario: Existing settings.local.json with other config
// ---------------------------------------------------------------------------
describe("Merge with existing settings", () => {
  it("preserves existing non-Brain env vars and non-env config keys", () => {
    const settingsPath = path.join(claudeDir, "settings.local.json");

    // Given a repo with .claude/settings.local.json containing other env vars
    const existingConfig = {
      env: {
        MY_CUSTOM_VAR: "keep-this",
        ANOTHER_VAR: "also-keep",
      },
      permissions: {
        allow: ["Read", "Write"],
      },
    };
    fs.writeFileSync(settingsPath, JSON.stringify(existingConfig, undefined, 2));

    // When the proxy setup step runs
    writeSettingsLocal(settingsPath, "https://brain.example.com", "brp_xyz789");

    // Then the env keys are merged (not overwritten)
    const result = JSON.parse(fs.readFileSync(settingsPath, "utf-8"));
    expect(result.env.ANTHROPIC_BASE_URL).toBe("https://brain.example.com/proxy/llm/anthropic");
    expect(result.env.ANTHROPIC_HEADERS).toBe("X-Brain-Auth: brp_xyz789");

    // And existing non-Brain env vars are preserved
    expect(result.env.MY_CUSTOM_VAR).toBe("keep-this");
    expect(result.env.ANOTHER_VAR).toBe("also-keep");

    // And existing non-env config keys are preserved
    expect(result.permissions.allow).toEqual(["Read", "Write"]);
  });
});

// ---------------------------------------------------------------------------
// Scenario: Re-running brain init updates proxy token
// ---------------------------------------------------------------------------
describe("Re-run updates token in place", () => {
  it("replaces proxy token while preserving all other settings", () => {
    const settingsPath = path.join(claudeDir, "settings.local.json");

    // Given a repo already configured with proxy settings
    writeSettingsLocal(settingsPath, "https://brain.example.com", "brp_old_token");

    // Simulate additional non-Brain keys that should survive
    const config = JSON.parse(fs.readFileSync(settingsPath, "utf-8"));
    config.env.SOME_OTHER_KEY = "preserve-me";
    fs.writeFileSync(settingsPath, JSON.stringify(config, undefined, 2));

    // When the user runs brain init again with a new token
    writeSettingsLocal(settingsPath, "https://brain.example.com", "brp_new_token");

    // Then .claude/settings.local.json is updated with the new token
    const result = JSON.parse(fs.readFileSync(settingsPath, "utf-8"));
    expect(result.env.ANTHROPIC_HEADERS).toBe("X-Brain-Auth: brp_new_token");

    // And the base URL and other keys are unchanged
    expect(result.env.ANTHROPIC_BASE_URL).toBe("https://brain.example.com/proxy/llm/anthropic");
    expect(result.env.SOME_OTHER_KEY).toBe("preserve-me");
  });
});

// ---------------------------------------------------------------------------
// Scenario: .gitignore verification
// ---------------------------------------------------------------------------
describe("Gitignore verification", () => {
  it("detects when settings.local.json is not in .gitignore", () => {
    const settingsPath = path.join(claudeDir, "settings.local.json");

    // Given a repo where .claude/settings.local.json is not in .gitignore
    // (no .gitignore exists)
    expect(isGitignored(repoDir, settingsPath)).toBe(false);
  });

  it("detects when settings.local.json IS properly gitignored", () => {
    const settingsPath = path.join(claudeDir, "settings.local.json");

    // Given a repo where .gitignore contains the settings path
    fs.writeFileSync(
      path.join(repoDir, ".gitignore"),
      ".claude/settings.local.json\n",
    );

    // Then the check detects it is gitignored
    expect(isGitignored(repoDir, settingsPath)).toBe(true);
  });
});

// ---------------------------------------------------------------------------
// Scenario: ~/.brain/config.json proxy token storage
// ---------------------------------------------------------------------------
describe("Brain config proxy token storage", () => {
  it("stores proxy_token and proxy_token_expires_at in repo config entry", () => {
    const configPath = path.join(tmpDir, "config.json");

    // Given an existing ~/.brain/config.json with a repo entry
    const existingConfig = {
      repos: {
        "/Users/priya/project": {
          server_url: "https://brain.example.com",
          workspace_id: "ws-123",
          access_token: "existing-oauth-token",
        },
      },
    };
    fs.writeFileSync(configPath, JSON.stringify(existingConfig, undefined, 2));

    // When brain init Step 7 stores the proxy token
    const config = JSON.parse(fs.readFileSync(configPath, "utf-8"));
    const repoEntry = config.repos["/Users/priya/project"];
    repoEntry.proxy_token = "brp_stored_token";
    repoEntry.proxy_token_expires_at = "2026-06-14T00:00:00Z";
    fs.writeFileSync(configPath, JSON.stringify(config, undefined, 2));

    // Then the proxy token is stored alongside existing config
    const result = JSON.parse(fs.readFileSync(configPath, "utf-8"));
    const entry = result.repos["/Users/priya/project"];
    expect(entry.proxy_token).toBe("brp_stored_token");
    expect(entry.proxy_token_expires_at).toBe("2026-06-14T00:00:00Z");

    // And existing fields are preserved
    expect(entry.server_url).toBe("https://brain.example.com");
    expect(entry.workspace_id).toBe("ws-123");
    expect(entry.access_token).toBe("existing-oauth-token");
  });
});

// ---------------------------------------------------------------------------
// Scenario: No fallback to direct Anthropic
// ---------------------------------------------------------------------------
describe("No fallback to direct Anthropic", () => {
  it("settings.local.json always points to Brain proxy, never direct Anthropic URL", () => {
    const settingsPath = path.join(claudeDir, "settings.local.json");

    writeSettingsLocal(settingsPath, "https://brain.example.com", "brp_token");

    const result = JSON.parse(fs.readFileSync(settingsPath, "utf-8"));

    // The base URL must point to Brain proxy, never to api.anthropic.com
    expect(result.env.ANTHROPIC_BASE_URL).not.toContain("api.anthropic.com");
    expect(result.env.ANTHROPIC_BASE_URL).toContain("/proxy/llm/anthropic");
  });
});

